    93→const MapDecorations: React.FC<{ path: [number, number][] }> = ({ path }) => {
    94→  const map = useMap();
    95→  useEffect(() => {
    96→    if (path.length < 2) return;
    97→    const polyline = L.polyline(path);
    98→    const decorator = L.polylineDecorator(polyline, {
    99→      patterns: [
   100→        { offset: '15%', repeat: '20%', symbol: (L as any).Symbol.arrowHead({ pixelSize: 14, polygon: true, pathOptions: { stroke: false, fill: true, color: '#FFFFFF', fillOpacity: 1, weight: 1 } }) },
   101→        { offset: '15%', repeat: '20%', symbol: (L as any).Symbol.arrowHead({ pixelSize: 14, polygon: false, pathOptions: { stroke: true, color: '#000000', weight: 2, opacity: 0.5 } }) }
   102→      ]
   103→    });
   104→    decorator.addTo(map);
   105→    return () => { map.removeLayer(decorator); };
   106→  }, [map, path]);
   107→  return null;
   108→}
