   120→interface ViewportPOIHandlerProps {
   121→  showHospitals: boolean;
   122→  showCustomers: boolean;
   123→  pois: any[];
   124→  setPois: React.Dispatch<React.SetStateAction<any[]>>;
   125→  setPoiLoading: (v: boolean) => void;
   126→  selDiv: string;
