   131→  selTerr: string;
   132→}
   133→
   134→const ViewportPOIHandler: React.FC<ViewportPOIHandlerProps> = ({ 
   135→  showHospitals, showCustomers, pois, setPois, setPoiLoading,
   136→  selDiv, selNH, selZone, selRegion, selArea, selTerr
   137→}) => {
   138→  const map = useMap();
   139→  const fetchTimerRef = useRef<NodeJS.Timeout | null>(null);
   140→  const lastFetchedBounds = useRef<string>('');
   141→
   142→  const fetchInView = () => {
   143→    if (!showHospitals && !showCustomers) {
   144→      if (pois.length > 0) setPois([]);
   145→      return;
   146→    }
   147→    const zoom = map.getZoom();
   148→    if (zoom < 11) {
   149→      if (pois.length > 0) setPois([]);
   150→      return;
   151→    }
   152→    const bounds = map.getBounds();
   153→    if (!bounds) return;
   154→    const sw = bounds.getSouthWest();
   155→    const ne = bounds.getNorthEast();
   156→    const boundsKey = `${sw.lat.toFixed(3)},${sw.lng.toFixed(3)},${ne.lat.toFixed(3)},${ne.lng.toFixed(3)}-${selDiv}-${selNH}-${selZone}-${selRegion}-${selArea}-${selTerr}`;
   157→    if (boundsKey === lastFetchedBounds.current) return;
   158→    lastFetchedBounds.current = boundsKey;
   159→    const latBuffer = (ne.lat - sw.lat) * 0.1;
   160→    const lngBuffer = (ne.lng - sw.lng) * 0.1;
   161→    const params = new URLSearchParams({
   162→      minLat: (sw.lat - latBuffer).toString(), maxLat: (ne.lat + latBuffer).toString(),
   163→      minLng: (sw.lng - lngBuffer).toString(), maxLng: (ne.lng + lngBuffer).toString(),
   164→      selDiv, selNH, selZone, selRegion, selArea, selTerr
   165→    });
   166→    setPoiLoading(true);
   167→    fetch(`/api/poi?${params.toString()}`).then(res => res.json()).then(data => setPois(data)).catch(console.error).finally(() => setPoiLoading(false));
   168→  };
   169→
   170→  useEffect(() => {
   171→    const onMoveEnd = () => {
   172→      if (fetchTimerRef.current) clearTimeout(fetchTimerRef.current);
   173→      fetchTimerRef.current = setTimeout(fetchInView, 500);
   174→    };
   175→    map.on('moveend', onMoveEnd);
   176→    fetchInView();
   177→    return () => { map.off('moveend', onMoveEnd); if (fetchTimerRef.current) clearTimeout(fetchTimerRef.current); };
   178→  }, [map, showHospitals, showCustomers, selDiv, selNH, selZone, selRegion, selArea, selTerr]);
   179→  return null;
   180→};
